import base64
import os

def write_b64_file(filepath, b64_str):
    os.makedirs(os.path.dirname(filepath), exist_ok=True)
    with open(filepath, 'wb') as f:
        f.write(base64.b64decode(b64_str.encode('utf-8')))
    print(f"Successfully wrote {filepath}")

